}

const firstJson = items[0].json;

// 3. Get webhook data directly from Webhook node
const webhook = $('Webhook').first().json;
const skillName = webhook.body?.skillName || 'Unknown Skill';
const context = webhook.body?.context || '';

// 4. Get hard array from Code5 output
const hardArray = firstJson.hard || [];

// 5. Handle empty array - return empty to prevent downstream issues
if (hardArray.length === 0) {
  return [];
}

// 6. Build initial transformed items
const transformedItems = hardArray.map(skill => ({
  json: {
    skill,
    difficulty: 'hard',
    skillName: skillName,
    context: context,
  }
}));

// 7. Position-assignment setup
const positions = ['A', 'B', 'C', 'D'];
const maxSameInRow = 2;
const positionHistory = [];
const positionCounts = positions.reduce((acc, p) => { acc[p] = 0; return acc; }, {});

// 8. Helper to pick a random element
const getRandomElement = arr =>
  arr && arr.length ? arr[Math.floor(Math.random() * arr.length)] : null;

// 9. Assign balanced positions
const outputItems = transformedItems.map((item, idx) => {
  let chosenPosition = null;
  let attempts = 0;
  const maxAttempts = positions.length * 3;

  do {
    attempts++;

    // a) Check for N-in-a-row violation
    let forbidden = null;
    if (positionHistory.length >= maxSameInRow) {
      const recent = positionHistory.slice(-maxSameInRow);
      if (recent.every(p => p === recent[0])) {
        forbidden = recent[0];
      }
    }

    // b) Determine available positions
    const available = forbidden
      ? positions.filter(p => p !== forbidden)
      : positions;

    // c) If none left, fallback to any
    if (available.length === 0) {
      chosenPosition = getRandomElement(positions);
      break;
    }

    // d) Choose among the least-used
    const minCount = Math.min(...available.map(p => positionCounts[p]));
    const leastUsed = available.filter(p => positionCounts[p] === minCount);
    chosenPosition = getRandomElement(leastUsed);

    // e) Safety fallback after too many tries
    if (attempts >= maxAttempts && !chosenPosition) {
      chosenPosition = getRandomElement(available) || getRandomElement(positions);
      break;
    }
  } while (!chosenPosition && attempts < maxAttempts);

  // 10. Final fallback
  if (!chosenPosition) {
    chosenPosition = 'A';
  }

  // 11. Track and assign
  positionHistory.push(chosenPosition);
  positionCounts[chosenPosition]++;
  item.json.correctPosition = chosenPosition;

  return item;
});

// 12. Return the items
return outputItems;

