// Function to parse MCQ questions from text format
function parseMCQQuestions(input) {
  // Make sure input is a string and handle markdown code blocks
  if (typeof input !== 'string') {
    try {
      input = JSON.stringify(input);
    } catch (e) {
      input = String(input);
    }
  }

  // Handle markdown code blocks by removing language identifier
  input = input.replace(/```\w+\n/, '```\n');

  // Split the input by the triple backtick blocks
  const questionBlocks = input.split("```").filter(block => {
    // Remove markdown and other common formatting
    return block.trim().replace(/^markdown\n/i, '').trim() !== "";
  });

  const parsedQuestions = [];

  for (const block of questionBlocks) {
    // Remove any markdown syntax and trim
    const cleanBlock = block.replace(/^markdown\n/i, '').trim();
    const lines = cleanBlock.split("\n");

    const question = {
      "Question Type": "",
      "Difficulty Level": "",
      "Question Text": "",
      "Option (A)": "",
      "Option (B)": "",
      "Option (C)": "",
      "Option (D)": "",
      "Option (E)": "",
      "Correct Option (A/B/C/D)": "",
      "Answer Explanation": "",
      "Score": "",
      "Sub-Topics": "",
      "Author": "",
      "Topic": ""
    };

    let currentField = null;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();

      // Enhanced field detection with more flexible matching
      const fieldMatch = line.match(/^([^:]+)\s*:\s*(.*)$/);

      if (fieldMatch) {
        const fieldName = fieldMatch[1].trim();
        const fieldValue = fieldMatch[2].trim();

        switch(fieldName) {
          case "Question Type":
            question["Question Type"] = fieldValue;
            currentField = "Question Type";
            break;

          case "Difficulty Level":
            question["Difficulty Level"] = fieldValue;
            currentField = "Difficulty Level";
            break;

          case "Question Text":
            question["Question Text"] = fieldValue;
            currentField = "Question Text";
            break;

          case (fieldName.match(/^Option \([A-E]\)$/) || {}).input:
            const optionLetter = fieldName.match(/\(([A-E])\)/)[1];
            question[`Option (${optionLetter})`] = fieldValue;
            currentField = "Option";
            break;

          case (fieldName.match(/^Correct Option.*$/) || {}).input:
            const correctOption = fieldValue.match(/[A-D]/);
            if (correctOption) {
              question["Correct Option (A/B/C/D)"] = correctOption[0];
            }
            currentField = "Correct Option";
            break;

          case "Answer Explanation":
            question["Answer Explanation"] = fieldValue;
            currentField = "Answer Explanation";
            break;

          case "Score":
            question["Score"] = fieldValue;
            currentField = "Score";
            break;

          case "Sub-Topics":
            question["Sub-Topics"] = fieldValue;
            currentField = "Sub-Topics";
            break;

          case "Author":
            question["Author"] = fieldValue;
            currentField = "Author";
            break;

          case "Topic":
            question["Topic"] = fieldValue;
            currentField = "Topic";
            break;
        }
      } else if (currentField === "Question Text" || currentField === "Answer Explanation") {
        // Continue adding to multi-line fields if we haven't reached a new field
        if (!line.match(/^(Option \([A-E]\)|Correct Option|Score|Sub-Topics|Author|Topic)/)) {
          question[currentField] += " " + line;
        } else {
          i--; // Go back one line to process this as a new field
          currentField = null;
        }
      }
    }

    // Clean up the parsed question
    Object.keys(question).forEach(key => {
      if (typeof question[key] === 'string') {
        question[key] = question[key].trim();
      }
    });

    // Only add the question if it has essential data
    if (question["Question Text"] && question["Question Type"]) {
      parsedQuestions.push(question);
    }
  }

  return parsedQuestions;
}

// Process input items
function processInputItems(items) {
  const results = [];

  for (const item of items) {
    try {
      let inputData = item.json;

      if (typeof inputData === 'string') {
        const parsedQuestions = parseMCQQuestions(inputData);
        results.push(...parsedQuestions.map(q => ({ json: q })));
      } else if (inputData && typeof inputData === 'object') {
        if (typeof inputData.input === 'string') {
          const parsedQuestions = parseMCQQuestions(inputData.input);
          results.push(...parsedQuestions.map(q => ({ json: q })));
        } else {
          let foundQuestions = false;

          for (const key in inputData) {
            if (typeof inputData[key] === 'string' && 
                (inputData[key].includes('Question Type:') || 
                 inputData[key].includes('```'))) {
              const parsedQuestions = parseMCQQuestions(inputData[key]);
              if (parsedQuestions.length > 0) {
                results.push(...parsedQuestions.map(q => ({ json: q })));
                foundQuestions = true;
              }
            }
          }

          if (!foundQuestions) {
            const parsedQuestions = parseMCQQuestions(JSON.stringify(inputData));
            results.push(...parsedQuestions.map(q => ({ json: q })));
          }
        }
      }
    } catch (error) {
      console.error(`Error processing item: ${error.message}`);
    }
  }

  return results.length > 0 ? results : [{ json: { "Error": "No questions could be parsed from the input" } }];
}

// Main execution
const items = $input.all();
return processInputItems(items);

