const items = $input.all();

const easy = [];
const medium = [];
const hard = [];

// Helpers
const get = (obj, path) => path.split('.').reduce((o, k) => (o && o[k] != null ? o[k] : undefined), obj);
const toInt = (v) => {
  const n = parseInt(v, 10);
  return Number.isNaN(n) ? undefined : n;
};
const findCounts = () => {
  for (const it of items) {
    const j = it?.json || {};
    const candidates = [
      ['body.easyQuestions', 'body.mediumQuestions', 'body.hardQuestions'],
      ['easyQuestions', 'mediumQuestions', 'hardQuestions'],
      ['params.easyQuestions', 'params.mediumQuestions', 'params.hardQuestions'],
      ['meta.easyQuestions', 'meta.mediumQuestions', 'meta.hardQuestions'],
      ['metadata.easyQuestions', 'metadata.mediumQuestions', 'metadata.hardQuestions'],
    ];
    for (const [eKey, mKey, hKey] of candidates) {
      const e = toInt(get(j, eKey));
      const m = toInt(get(j, mKey));
      const h = toInt(get(j, hKey));
      if ([e, m, h].every((x) => typeof x === 'number')) {
        return { easy: e, medium: m, hard: h };
      }
    }
  }
  return null;
};

// Collect raw text from common locations
const textPieces = [];
for (const it of items) {
  const j = it?.json;
  if (typeof it?.text === 'string') textPieces.push(it.text);
  if (j && typeof j === 'string') textPieces.push(j);
  if (j && typeof j.text === 'string') textPieces.push(j.text);
  if (j && typeof j.output === 'string') textPieces.push(j.output);
  if (j && typeof j.response === 'string') textPieces.push(j.response);
}
const combinedRawText = textPieces.join('\n');
console.log('Combined raw text:', combinedRawText);

// Normalize newlines and split
const processedText = combinedRawText
  .replace(/\r\n/g, '\n')
  .replace(/\\n/g, '\n')
  .replace(/\u2028|\u2029/g, '\n');

console.log('Processed text:', processedText);

// Clean and split into lines
const lines = processedText
  .split('\n')
  .map(l => l.replace(/\u200B/g, '').trim())
  .filter(l => l.length > 0);

console.log('Lines:', lines);

// Check for explicit headers
const hasHeaders = lines.some(l => /^\[?\s*(EASY|MEDIUM|HARD)\b/i.test(l));

// Utility: extract numbered lines as { num, skill }
const extractNumbered = (arr) => {
  const out = [];
  for (const line of arr) {
    const m = line.match(/^(\d+)\.\s*(.+)$/);
    if (m) {
      const num = parseInt(m[1], 10);
      const skill = m[2].trim();
      if (skill) out.push({ num, skill });
    }
  }
  return out;
};

if (hasHeaders) {
  // Header-based parsing
  let currentSection = '';
  for (const line of lines) {
    if (/^\[?\s*EASY\b/i.test(line)) { currentSection = 'easy'; continue; }
    if (/^\[?\s*MEDIUM\b/i.test(line)) { currentSection = 'medium'; continue; }
    if (/^\[?\s*HARD\b/i.test(line)) { currentSection = 'hard'; continue; }

    const m = line.match(/^(\d+)\.\s*(.+)$/);
    if (m && currentSection) {
      const skill = m[2].trim();
      if (!skill) continue;
      if (currentSection === 'easy') easy.push(skill);
      else if (currentSection === 'medium') medium.push(skill);
      else if (currentSection === 'hard') hard.push(skill);
    }
  }
} else {
  // Headerless parsing
  const numbered = extractNumbered(lines);
  console.log('Numbered items:', numbered);

  const counts = findCounts();

  if (counts) {
    const totalNeeded = counts.easy + counts.medium + counts.hard;
    if (numbered.length < totalNeeded) {
      console.warn(`Warning: fewer items (${numbered.length}) than requested total (${totalNeeded}). Proceeding with available items.`);
    }
    easy.push(...numbered.slice(0, counts.easy).map(x => x.skill));
    medium.push(...numbered.slice(counts.easy, counts.easy + counts.medium).map(x => x.skill));
    hard.push(...numbered.slice(counts.easy + counts.medium, counts.easy + counts.medium + counts.hard).map(x => x.skill));
  } else {
    // Use numbering resets to determine sections: 1. => next section
    let sectionIndex = -1; // -1: not started, 0: easy, 1: medium, 2+: hard
    for (const item of numbered) {
      if (item.num === 1) sectionIndex += 1;
      const section = sectionIndex <= 0 ? 'easy' : sectionIndex === 1 ? 'medium' : 'hard';
      if (section === 'easy') easy.push(item.skill);
      else if (section === 'medium') medium.push(item.skill);
      else hard.push(item.skill);
    }
  }
}

console.log('Final arrays:', { easy, medium, hard });

